"""
Fill script: mkt-original, Judges 9–10, missing verses.
Ch 9: vv 3,6,10-13,16-22,25-52,55-56 (43 missing)
Ch 10: vv 2,4,5,8,9,11-13,15,17,18 (11 missing)

Judges 9 — Abimelech: anti-covenant kingship, the bramble-king fable, and
YHWH's retributive justice (divine passive) working through a woman.
Key philological themes: māšal (parable/rule), Baal-Berith vs. El-berith,
the Shechem covenant oak, ḥāmās (violence/bloodguilt) as moral causation.

Judges 10 — minor judges + the seventh apostasy cycle. YHWH's unusual direct
speech (v11-14) uses the exodus-deliverance catalogue as basis for refusing
rescue, then relents (v16) when Israel genuinely removes foreign gods.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JUDGES_FILL = {
  "9": {
    "3": "<p><em>waydabbərû ʾăḥê-ʾimmô ʿālāyw bəʾoznê kol-baʿălê šekem ʾēt kol-haddəḇārîm hāʾēlleh wayyēt libbām ʾaḥărê ʾăḇîmeleḵ kî ʾāmərû ʾāḥînû hûʾ</em> — 'His mother's brothers spoke all these words on his behalf in the ears of all the lords of Shechem, and their heart inclined (<em>wayyēt libbām</em>) after Abimelech, for they said: He is our brother.' <em>nāṭāh lēḇ</em> (H5186 H3820, to incline the heart) is the vocabulary of spiritual seduction: Solomon's wives 'inclined his heart after other gods' (1 Kgs 11:2-3, same phrase). The Shechemites' kinship appeal ('he is our brother') mirrors the technique of every false leader: ethnic solidarity is invoked to bypass moral reasoning. Their hearts turned before a word of his competence or character was mentioned.</p>",
    "6": "<p><em>wayyēʾāsəpû kol-baʿălê šekem wəkol-bêt millôʾ wayyēlkû wayyamlîkû ʾet-ʾăḇîmeleḵ ʾeṣel ʾēlôn muṣṣāḇ ʾăšer bišekem</em> — 'All the lords of Shechem and all Beth-millo gathered together and went and made Abimelech king beside the oak of the pillar that is at Shechem.' <em>ʾēlôn muṣṣāḇ</em> (H437 H4676, oak of the standing pillar) is almost certainly the covenant oak of Josh 24:26, where Joshua erected a great stone as witness to the covenant renewal at Shechem. Israel's most solemn covenant site is now the coronation venue for a blood-bought bramble-king. The narrator's geography is his theology: covenant space is being desecrated by anti-covenant kingship.</p>",
    "10": "<p><em>wayyōʾmərû hāʿēṣîm ʾel-hattəʾēnāh ləḵî-ʾat malkî ʿālênû</em> — 'The trees said to the fig tree: Come, you reign over us.' The fig tree is the second tree in Jotham's fable. In OT covenant blessing, sitting 'under his vine and under his fig tree' (1 Kgs 4:25; Mic 4:4; Zech 3:10) is the idiom for shalom under good kingship. The fig tree's <em>mātôq</em> (sweetness) and <em>tənûḇātî haṭṭôḇāh</em> (good fruit) represent the covenant fruitfulness that genuine national leadership produces. Asking the fig tree to be king is asking it to abandon the very quality that makes it valuable.</p>",
    "11": "<p><em>wattoʾmer lāhem hattəʾēnāh heḥādaltî ʾet-matkî wəʾet-tənûḇātî haṭṭôḇāh ûhālaktî lānûaʿ ʿal-hāʿēṣîm</em> — 'The fig tree said to them: Shall I leave my sweetness (<em>mātôq</em>) and my good fruit, and go to sway over the trees?' <em>nûaʿ</em> (H5128, to sway, shake, wander) — the verb of instability. The fig tree would exchange productive fruitfulness for anxious instability. This is Jotham's embedded critique of Abimelech's offer: power requires the fig tree (= Gideon's sons) to abandon what gives it its value. True vocation produces fruit; false vocation produces only swaying — a rootless, restless motion without yield.</p>",
    "12": "<p><em>wayyōʾmərû hāʿēṣîm ʾel-haggāpen ləḵî ʾat malkî ʿālênû</em> — 'Then the trees said to the vine: Come, you reign over us.' The vine is the third tree solicited. Wine (<em>tîrôš</em>) 'gladdens God and men' (v13) — the language echoes Ps 104:15 ('wine to gladden the heart of man') and Noah's cultivation of the vine as covenant restoration after the flood. The vine's joy-producing fruit is a covenant gift; the Nazirite vow of abstinence (cf. Samson, ch13) and the priestly prohibition (Lev 10:9) treat wine as powerful and sacred. The vine in Jotham's fable carries the weight of covenant celebration.</p>",
    "13": "<p><em>wattoʾmer lāhem haggāpen heḥādaltî ʾet-tîrôšî hamməśammēaḥ ʾĕlōhîm wăʾănāšîm ûhālaktî lānûaʿ ʿal-hāʿēṣîm</em> — 'The vine said to them: Shall I leave my wine (<em>tîrôšî</em>) that gladdens God and men, and go to sway over the trees?' <em>śāmaḥ ʾĕlōhîm wăʾănāšîm</em> (gladdens God and men) — wine participates in divine-human joy in worship (grain and new wine as covenant provision, Deut 14:23; the drink offering, Num 15:5-10). The vine's self-understanding — it exists for God's and humanity's joy — is the theological ideal of vocation. Abimelech is a bramble that destroys rather than a vine that delights.</p>",
    "16": "<p><em>wəʿattāh ʾim-beʾĕmet ûḇetāmîm ʿăśîtem wayyamlikû ʾet-ʾăḇîmeleḵ wəʾim-ṭôḇāh ʿăśîtem ʿim-yərubbaʿal ûʿim-bêtô</em> — 'And now, if you acted in good faith (<em>beʾĕmet</em>) and integrity (<em>ḇetāmîm</em>) when you made Abimelech king, and if you have dealt well with Jerubbaal and his house...' <em>ʾemet</em> (H571, truth, faithfulness, reliability) and <em>tāmîm</em> (H8549, integrity, wholeness, blamelessness — used of Noah in Gen 6:9 and of covenant requirement in Deut 18:13) are the twin covenant virtue-words. Jotham invokes the standard of covenant righteousness to expose the Shechemites' action as its opposite.</p>",
    "17": "<p><em>kî-nālaḥam ʾăḇî ʿălêkem wayyašlēk ʾet-napšô minaggεd wayyaṣṣêl ʾetkem miyyaḏ miḏyān</em> — 'For my father fought for you, and he risked (<em>wayyašlēk</em>) his life from before you, and he delivered you from the hand of Midian.' <em>šillēaḥ ʾet-napšô minaggεd</em> (H7971 H5315, threw his life before him/risked his life) — the idiom for self-sacrificial endangerment in battle (cf. 2 Sam 23:17). Gideon/Jerubbaal delivered the very community that is now rewarding his house with massacre (v5). The contrast between Gideon's self-giving and Abimelech's self-aggrandizement is the moral center of Jotham's speech.</p>",
    "18": "<p><em>wəʾattem qamtem ʿal-bêt ʾāḇî hayyôm hazzeh watthargû ʾet-bānāyw šibʿîm ʾîš ʿal-ʾeḇen ʾaḥāt wayyamlikû ʾet-ʾăḇîmeleḵ ben-ʾămātô ʿal-baʿălê šekem kî ʾăḥîkem hûʾ</em> — 'Yet you have risen up against my father's house today and have killed his sons, seventy men, on one stone, and have made Abimelech, the son of his slave woman, king over the lords of Shechem because he is your brother.' The accusation is structured as covenant lawsuit: Gideon's service (v17) placed them under obligation; their murder of seventy on one stone (v5) violated that covenant. <em>ʾeḇen ʾaḥāt</em> (one stone) — an execution altar, the instrument of mass kinship-killing by the man funded with temple-silver (v4).</p>",
    "19": "<p><em>wəʾim-beʾĕmet ûḇetāmîm ʿăśîtem ʿim-yərubbaʿal ûʿim-bêtô hayyôm hazzeh śimḥû bă-ʾăḇîmeleḵ wəyiśmaḥ gam-hûʾ bākem</em> — 'If you have then acted in good faith and integrity with Jerubbaal and his house this day, rejoice in Abimelech, and let him also rejoice in you.' The conditional is rhetorical: Jotham has already demonstrated the condition has not been met. The ironic invitation to rejoice in the bramble-king they chose functions as prophetic sarcasm — the same form as Amos 4:4 ('Come to Bethel and transgress'). The joy will be short-lived; the bramble will consume them.</p>",
    "20": "<p><em>wəʾim-ʾayin tēṣēʾ ʾēš mēʾăḇîmeleḵ wətoʾkal ʾet-baʿălê šekem wəʾet-bêt millôʾ wətēṣēʾ ʾēš mibbaʿălê šekem ûmibêt millôʾ wətoʾkal ʾet-ʾăḇîmeleḵ</em> — 'But if not, let fire come out from Abimelech and devour the lords of Shechem and Beth-millo; and let fire come out from the lords of Shechem and Beth-millo and devour Abimelech.' Jotham's curse employs the bramble's own imagery (v15: 'let fire come out of the bramble and devour') back upon both parties. The mutual-destruction formula is a covenant curse (cf. Deut 27-28): those who violate covenant obligations will be destroyed by their own choices. Both Abimelech (v53-54) and Shechem (v45-49) will indeed be consumed — the bramble fulfilled its fable-function exactly.</p>",
    "21": "<p><em>wayyānos yôṯām wayyiḇraḥ wayyēlek bəʾērāh wayyēšeḇ šām mippənê ʾăḇîmeleḵ ʾāḥîw</em> — 'Jotham fled and ran away and went to Beer, and he settled there because of Abimelech his brother.' <em>yānos…wayyiḇraḥ</em> (H5127, fled, and H1272, ran/escaped) — the doubling of flight verbs emphasizes urgency. Jotham's fate is the righteous witness who must flee after truth-telling; he cannot enforce the curse he has pronounced. The curse is left to YHWH's sovereign working (v23: God sent an evil spirit). Beer (<em>bəʾēr</em>, well) is unknown but its etymology ('well/water-source') may carry the narrative irony of Jotham finding refuge where there is sustenance amid spiritual drought.</p>",
    "22": "<p><em>wayyāśar ʾăḇîmeleḵ ʿal-yiśrāʾēl šālôš šānîm</em> — 'Abimelech ruled over Israel for three years.' <em>śārar</em> (H8280/H8323, to rule/act as prince) — not the usual <em>šāpaṭ</em> (judge) of the other deliverers; Abimelech rules as a political prince/tyrant, not as a covenant-judge raised by YHWH. The 'three years' is the precise duration before the divine retribution mechanism (the evil spirit of v23) is activated — a short enough reign to make clear that Abimelech's kingship never stabilized. Three years echoes nothing in covenant history; it is simply the measure of how long YHWH delayed before dismantling the anti-covenant experiment.</p>",
    "25": "<p><em>wayyāśîmû lô baʿălê šekem mĕʾarəḇîm ʿal rāʾšê hehārîm wayyiggənzəlû ʾet kol-ʾăšer-yəʿăḇōr ʿălêhem haddārek wayyuggad lăʾăḇîmeleḵ</em> — 'The lords of Shechem set ambushes against him on the mountaintops, and they robbed everyone who passed by them on the road; and it was reported to Abimelech.' The 'evil spirit' of v23 has worked: Shechem's treachery against their own chosen king takes the form of highway robbery (<em>gāzal</em>, H1497, to plunder by violence). The covenant community has collapsed: social order, property security, and political loyalty have all unraveled simultaneously — the precise conditions Jotham's curse predicted.</p>",
    "26": "<p><em>wayyāḇōʾ Gaʿal ben-ʿEḇed wəʾeḥāyw wayyaʿaḇrû bišekem wayyiḇtəḥû-ḇô baʿălê šekem</em> — 'Gaal the son of Ebed came with his relatives and passed into Shechem, and the lords of Shechem put their trust in him.' The sudden appearance of Gaal ('loathing'? — the name's etymology is disputed but possibly pejorative) and his anonymous father Ebed ('servant') creates a figure of no pedigree or legitimate authority. <em>bāṭaḥ</em> (H982, to trust, be confident in) — the Shechemites transfer their political trust from Abimelech to Gaal; the evil spirit of v23 has produced the promised fragmentation between Abimelech and Shechem.</p>",
    "27": "<p><em>wayyēṣəʾû haśśādeh wayyibṣərû ʾet-karmêhem wayyidrakû wayyaʿăśû hillûlîm wayyāḇōʾû bêt ʾĕlōhêhem wayyōʾklû wayyishtû wayqallalû ʾet-ʾăḇîmeleḵ</em> — 'They went out into the field and gathered grapes from their vineyards, trod them, and held <em>hillulim</em>, and went into the house of their god, and ate and drank and cursed Abimelech.' <em>hillûlîm</em> (H1974, festive praise/celebration — from <em>hālal</em>) is the term for the vintage celebration of the fourth year's fruit (Lev 19:24). That this festival ends with cursing (<em>qillēl</em>) their own king in the temple of Baal-Berith is the religious inversion: the harvest thanksgiving becomes a political conspiracy.</p>",
    "28": "<p><em>wayyōʾmer Gaʿal ben-ʿEḇed mî ʾăḇîmeleḵ ûmî-šekem kî naʿăḇādenô halōʾ-ben-yərubbaʿal ûzəḇul pəqîḏô ʿiḇdû ʾet-ʾanšê ḥămôr ʾăḇî šekem ûmadduaʿ naʿăḇādenô ʾănaḥnû</em> — 'Gaal the son of Ebed said: Who is Abimelech, and who is Shechem, that we should serve him? Is he not the son of Jerubbaal, and is not Zebul his officer? Serve the men of Hamor the father of Shechem! Why should we serve him?' Gaal's appeal invokes the pre-Israelite Shechemite identity: Hamor (<em>ḥămôr</em>, H2544, donkey — the name of Shechem's original patriarch, Gen 34:2) represents the Canaanite legitimacy claim against Israelite political control. The demagogue offers a Canaanite identity revival against the Israelite hybrid Abimelech.</p>",
    "29": "<p><em>ûmî yittēn ʾet-hāʿām hazzeh bəyāḏî wəʾāsîrāh ʾet-ʾăḇîmeleḵ wayyōʾmer lăʾăḇîmeleḵ rabbēh ṣəḇāʾăkā waṣēʾ</em> — 'Would that this people were in my hand! Then I would remove Abimelech. He said to Abimelech: Increase your army and come out!' The taunt delivered second-hand (Gaal probably does not know Abimelech will hear) reveals the fatal overconfidence of the demagogue. <em>rāḇāh ṣəḇāʾ</em> (muster your army) — Gaal's dare is the opening that Zebul will use to destroy him. The evil spirit (v23) is working through political ambition and the boasting of an outsider who mistakes a festive crowd for an army.</p>",
    "30": "<p><em>wayyišmaʿ Zəḇul śar-hāʿîr ʾet-diḇrê Gaʿal ben-ʿEḇed wayyiḥar ʾappô</em> — 'When Zebul the commander of the city heard the words of Gaal the son of Ebed, his anger blazed.' <em>ṣar hāʿîr</em> (H8269 H5892, commander/official of the city) — Zebul holds the administrative position; his loyalty to Abimelech is positional, not personal. <em>ḥārāh ʾap</em> (H2734 H639, anger blazed/burned) — the same idiom used for YHWH's anger and for Samson's anger; here it is administrative outrage at political disloyalty. Zebul's response sets the trap that will destroy Gaal.</p>",
    "31": "<p><em>wayyišlaḥ malʾākîm ʾel-ʾăḇîmeleḵ bəṯormāh lēʾmōr hinnēh Gaʿal ben-ʿEḇed wəʾeḥāyw bāʾîm šəkemāh wəhinnām ṣārîm ʾet-hāʿîr ʿālêkā</em> — 'He sent messengers to Abimelech at Torma secretly, saying: Gaal the son of Ebed and his relatives have come to Shechem, and behold they are besieging the city against you.' <em>bəṯormāh</em> (secretly) — the adverb suggests clandestine communication; Zebul must act without Gaal knowing. The word may be the toponym Arumah (v41) or a common noun meaning 'by deceit.' Intelligence-reporting precedes military action; Zebul functions as Abimelech's inside man. The ironies multiply: the city that betrayed Abimelech now has his spy inside it.</p>",
    "32": "<p><em>wəʿattāh qûm laylāh ʾattāh wəhāʿām ʾăšer ʾittāk wəʾĕrōḇ baśśāḏeh</em> — 'So now, arise by night, you and the people who are with you, and set an ambush in the field.' Night ambush (<em>ʾāraḇ</em>, H693, to lie in wait) is the tactical element that exploits Gaal's exposed position at the city gate. The military advice is precise: position before dawn, rush at sunrise when Gaal comes out. The narrative pacing here shifts from fable and speech to rapid tactical action — the evil spirit of v23 has converted political fragmentation into open armed conflict.</p>",
    "33": "<p><em>wəhāyāh ḇabbōqer kizrōaḥ haššemeš taškim wāpāšaṭtā ʿal-hāʿîr wəhinnēh-hûʾ wəhāʿām ʾăšer-ʾittô yōṣəʾîm ʾēleykā wəʿāśîtā lô kaʾăšer timṣāʾ yāḏekā</em> — 'In the morning, when the sun rises, rise early and rush upon the city. When he and the people with him come out against you, do to him whatever your hand finds.' <em>pāšaṭ</em> (H6584, to rush, make a raid) — the Philistine raiding verb used against Israel; Abimelech uses against his own city the same military tactic used by Israel's enemies. The instruction 'do whatever your hand finds' (<em>taʿăśeh kaʾăšer timṣāʾ yāḏekā</em>) is the formula of improvised warfare — no covenant restraint, no divine command.</p>",
    "34": "<p><em>wayyāqom ʾăḇîmeleḵ wəkol-hāʿām ʾăšer-ʾittô laylāh wayyēʾāraḇû ʿal-šekem ʾarbaʿāh rāʾšîm</em> — 'Abimelech and all the people with him rose by night and set an ambush against Shechem in four companies.' Four companies (<em>ʾarbaʿāh rāʾšîm</em>, four heads/groups) is the standard tactical division for encirclement (cf. Gideon's three companies at Midian, 7:16; Saul's three companies, 1 Sam 11:11). The very tactics Gideon used against Midian are now being used by his son against Israelites. The inversion is the narrator's point: Abimelech militarizes the family of the judge against the judge's own people.</p>",
    "35": "<p><em>wayyēṣēʾ Gaʿal ben-ʿEḇed wayyaʿămōd petaḥ šáʿar hāʿîr wayyāqom ʾăḇîmeleḵ wəhāʿām ʾăšer-ʾittô min-hammaʾărāḇ</em> — 'Gaal the son of Ebed went out and stood at the entrance of the city gate, and Abimelech and the people with him arose from the ambush.' The city gate (<em>petaḥ šáʿar</em>) is the civic space for judicial proceedings and morning business; Gaal's appearance there is leadership display, not combat posture. He stepped into Zebul's trap: the gate exposes him to the ambush sprung by the dawn command of v33.</p>",
    "36": "<p><em>wayyarʾ Gaʿal ʾet-hāʿām wayyōʾmer ʾel-Zəḇul hinnēh ʿam yôrēd mērāʾšê hehārîm wayyōʾmer ʾēlāyw Zəḇul ʾēt ṣel hehārîm ʾattāh rōʾeh kāʾănāšîm</em> — 'When Gaal saw the people, he said to Zebul: Look, people are coming down from the mountaintops. But Zebul said to him: You are seeing the shadow of the mountains as men.' Zebul's deceptive reassurance ('you are seeing shadows') is the counterintelligence move: he delays Gaal's alert until Abimelech's forces are close enough. The irony is that Zebul is the man the Shechemites had trusted as their administrator — deception is now built into Shechem's own leadership structure.</p>",
    "37": "<p><em>wayyōsep ʿôḏ Gaʿal lədabbēr wayyōʾmer hinnēh ʿam yôrəḏîm mittabûr hāʾāreṣ wəraʾš ʾeḥāḏ bāʾ midderek ʾēlôn məʿônənîm</em> — 'Gaal spoke again and said: Look, people are coming down from the center of the land, and one company is coming from the direction of the Diviners' Oak (<em>ʾēlôn məʿônənîm</em>).' <em>ʾēlôn məʿônənîm</em> (Oak of the Diviners/Enchanters) — <em>ʿānan</em> (H6049) is the word for divination/augury; this oak is associated with forbidden practices (cf. Gen 12:6 — the oak of Moreh, a related cultic site). The geographical landmark encapsulates Shechem's syncretistic religious landscape: the covenant oak (v6) and the Diviners' Oak stand near each other.</p>",
    "38": "<p><em>wayyōʾmer ʾēlāyw Zəḇul ʾayyēh ʾēpôʾ pîkā ʾăšer tōʾmar mî ʾăḇîmeleḵ kî naʿăḇādenô halōʾ zeh hāʿām ʾăšer māʾastāh bô ṣēʾ-nāʾ ʿattāh wəhilāḥem bô</em> — 'Then Zebul said to him: Where is your big mouth now — when you said: Who is Abimelech that we should serve him? Is not this the people you despised? Go out now and fight with him!' Zebul's taunt throws Gaal's own words back at him (cf. v28). <em>pîkā ʾăšer tōʾmar</em> (your mouth that said) — the demagogue is held accountable to his own speech. His boast before a festival crowd ('increase your army and come out,' v29) is now the measure of his failure; the crowd is gone and the army is real.</p>",
    "39": "<p><em>wayyēṣēʾ Gaʿal lipnê baʿălê šekem wayyillāḥem bă-ʾăḇîmeleḵ</em> — 'Gaal went out at the head of the lords of Shechem and fought with Abimelech.' The brevity of the verse signals the futility of the engagement. Gaal has no choice: having been exposed by Zebul and challenged publicly, retreat would be fatal to his authority. He fights not because he has military advantage but because his boast demands action. The evil spirit (v23) has fulfilled its first purpose: it drove Abimelech and Shechem to open warfare.</p>",
    "40": "<p><em>wayyirdəpēhû ʾăḇîmeleḵ wayyānos mippānāyw wayyipləlû ḥălālîm rabbîm ʿaḏ petaḥ haššáʿar</em> — 'Abimelech chased him and he fled before him, and many fell slain as far as the entrance of the gate.' Gaal's rout — from open field back to the city gate — reverses his triumphant standing at the gate (v35). The gate that was his political platform becomes the boundary of his defeat. The slain falling to the very threshold of the city gate is the narrator's spatial irony: civic space (gate = judgment and leadership) is now the measure of military collapse.</p>",
    "41": "<p><em>wayyēšeḇ ʾăḇîmeleḵ bă-ʾărûmāh wayyəgāreš Zəḇul ʾet-Gaʿal wəʾet-ʾeḥāyw mišekem lāšeḇet</em> — 'Abimelech took up residence at Arumah, and Zebul drove out Gaal and his relatives so that they could not remain in Shechem.' Abimelech's withdrawal to Arumah while Zebul administers the expulsion shows the division of labor in coercive governance: the king controls the military outcome, the local official manages the political cleanup. Gaal is expelled — not killed — suggesting Zebul settles for political removal rather than bloodshed, perhaps to avoid triggering another cycle of ḥāmās (bloodguilt).</p>",
    "42": "<p><em>wayhî mimmoḥorat wayyēṣēʾ hāʿām haśśāḏeh wayyaggîḏû lăʾăḇîmeleḵ</em> — 'The next day the people of Shechem went out into the field, and it was reported to Abimelech.' Normal agricultural life (going to the field) resumes the day after the battle — the Shechemites assume Gaal's defeat closes the episode. Their unawareness of Abimelech's continued hostile intent is the dramatic irony the narrator builds for the mass slaughter of vv43-45. They go out to work; he goes out to kill.</p>",
    "43": "<p><em>wayyiqqaḥ ʾet-hāʿām wayyeḥălqēm lišlōšāh rāʾšîm wayyēʾĕrōḇ baśśāḏeh wayyarʾ wəhinnēh hāʿām yōṣēʾ min-hāʿîr wayyāqom ʿălêhem wayyakkēm</em> — 'He took the people and divided them into three companies and set ambushes in the fields. He watched and saw the people coming out of the city, and he rose against them and struck them.' Three companies again (cf. v34, Gideon's tactic) — Abimelech uses the judge-heritage's military methods to massacre civilians. The field-workers are not soldiers; they are farmers. The ambush against unarmed farmers completes the moral inversion: the anti-covenant king destroys the covenanted people's livelihood.</p>",
    "44": "<p><em>wă-ʾăḇîmeleḵ wəhārāʾšîm ʾăšer-ʾimmô pāšəṭû wayyaʿamdû petaḥ šáʿar hāʿîr ûšənê hārāʾšîm pāšəṭû ʿal kol-ʾăšer baśśāḏeh wayyakkûm</em> — 'Abimelech and his company rushed forward and stood at the gate of the city, while the two companies rushed upon all who were in the field and struck them.' The three-company pincer movement (city gate + both field flanks) replicates Gideon's tactical genius (7:20-22) but here applied to his own city. The gate company cuts off retreat; the field companies kill workers. The harvest becomes a massacre — <em>ḥāmās</em> returning on Abimelech's own head through the very tactics his father used for deliverance.</p>",
    "45": "<p><em>wă-ʾăḇîmeleḵ nilḥam bāʿîr kol-hayyôm hahûʾ wayyilkōd ʾet-hāʿîr wəʾet-hāʿām ʾăšer-bāh hārag wayyitōṣ ʾet-hāʿîr wayyizrāʿêhā mālaḥ</em> — 'Abimelech fought against the city all that day. He captured it and killed the people who were in it, and he demolished the city and sowed it with salt.' <em>wayyizrāʿêhā mālaḥ</em> (sowed it with salt) — the ritual destruction of a city by salt-sowing denies the ground covenant fruitfulness (Deut 29:23 uses salt as the curse-image for covenant violation). This is the ultimate anti-harvest: the one who cannot give covenant blessing salts the earth to prevent all future blessing. The city becomes a covenant-cursed waste, testifying to Jotham's prophecy.</p>",
    "46": "<p><em>wayyišmēʿû kol-baʿălê migdal-šekem wayyāḇōʾû ʾel ṣərîaḥ bêt ʾēl bərît</em> — 'When all the lords of the Tower of Shechem heard, they entered the stronghold (<em>ṣərîaḥ</em>) of El-berith.' The narrator reveals a second name for the Shechem temple: <em>Bêt ʾēl bərît</em> (house of El-berith, God of the covenant) alongside <em>Baal-Berith</em> (lord of the covenant, 8:33, 9:4). The equivalence of El-berith and Baal-Berith in the narrator's description suggests the deity was worshipped under both names — a 'covenant-god' (berît) that blended Canaanite and Israelite religious vocabulary. Taking refuge in the covenant-god's stronghold against the covenant-people's judge's son is the chapter's religious irony made spatial.</p>",
    "47": "<p><em>wayyuggad lăʾăḇîmeleḵ kî hiṯqabbaṣû kol-baʿălê migdal-šekem</em> — 'And it was reported to Abimelech that all the lords of the Tower of Shechem had gathered together.' The intelligence chain from v31 (Zebul's report to Abimelech) continues: Abimelech's surveillance of Shechem is total. The tower refugees believe they are safe — a stronghold with a covenant-deity's name provides no protection. The tower of El-berith will become their crematorium.</p>",
    "48": "<p><em>wayyaʿal ʾăḇîmeleḵ har-Ṣalmôn hûʾ wəkol-hāʿām ʾăšer ʾittô wayyiqqaḥ ʾăḇîmeleḵ ʾet-haqqardummôt bəyāḏô wayyikrōt śōkāh wayyiśśāʾ wayyāśem ʿal-šikmô wayyōʾmer ʾel-hāʿām ʾăšer-ʾittô mah-rəʾîtem ʿāśîtî mahărû ʿăśû kāmônî</em> — 'Abimelech went up to Mount Zalmon, he and all the people with him. Abimelech took an axe (<em>qardummôt</em>) in his hand, cut down a bundle of branches, lifted it, and put it on his shoulder, saying: What you have seen me do — hurry and do likewise.' The axe-and-branch scene is a narrative parody of royal leadership: the king carries wood like a laborer, his glory reduced to arson preparation. The command 'do as you have seen me do' parodies the legitimate teaching authority of the judge-deliverers who modeled covenant life.</p>",
    "49": "<p><em>wayyikrōt gam-kol-hāʿām ʾîš śōkāh wayyēlkû ʾaḥărê ʾăḇîmeleḵ wayyāśîmû ʿal-haṣṣərîaḥ wayyaṣṣîtû ʿălêhem ʾet-haṣṣərîaḥ bāʾēš wayyāmûtû gam-kol-ʾanšê migdal-šekem kəʾelep ʾîš wəʾiššāh</em> — 'Every one of the people also cut his bundle and followed Abimelech and set the branches against the stronghold, and they set the stronghold on fire with the people in it. So all the men of the Tower of Shechem also died, about a thousand men and women.' The thousand dead in the temple-stronghold fulfills Jotham's curse (v20: fire from Abimelech devours Shechem). The fire that consumes the Baal/El-berith stronghold — a covenant-deity's house — with all its worshippers is the covenant curse enacted: the house that funded Abimelech's seventy murders (v4) is destroyed by those murders' perpetrator.</p>",
    "50": "<p><em>wayyēlek ʾăḇîmeleḵ ʾel-Ṯêḇēṣ wayyaḥan ʿal-Ṯêḇēṣ wayyilkəḏāh</em> — 'Then Abimelech went to Thebez and encamped against Thebez and captured it.' The campaign continues beyond Shechem to Thebez (modern Tubas, northeast of Shechem), presumably a city allied with or dependent on Shechem. The rapid capture ('and he captured it') suggests minimal resistance — until the tower (v51). The narrative pause after 'captured it' before introducing the tower is literary suspense: Abimelech has seemingly crushed all resistance, but the instrument of his defeat has not yet appeared.</p>",
    "51": "<p><em>ûmiggdal-ʿōz hāyāh bəṯôk-hāʿîr wayyānûsû šāmmāh kol-hāʾănāšîm wəhannāšîm wəkol baʿălê hāʿîr wayyisgərû baʿăḏām wayyaʿălû ʿal-gag hammiggdāl</em> — 'But there was a strong tower within the city, and all the men, women, and all the lords of the city fled to it, locked themselves in, and went up onto the roof of the tower.' <em>miggdal-ʿōz</em> (H4026 H5797, tower of strength) — the tower refuge that defeated Abimelech is the same architectural type as the tower of Babel (H4026, Gen 11:4) and the towers of later military architecture. The women and men together on the tower roof anticipates the instrument of Abimelech's death: a woman on a roof (v53). The strong tower that sheltered a woman becomes the platform for his judgment.</p>",
    "52": "<p><em>wayyāḇōʾ ʾăḇîmeleḵ ʿaḏ-hammiggdāl wayyillāḥem bô wayyiggaš ʾel-petaḥ hammiggdāl ləśorpô bāʾēš</em> — 'Abimelech came to the tower and fought against it and approached the door of the tower to set it on fire.' The repetition of his Shechem tactic (fire) demonstrates that Abimelech has one tool: arson. What destroyed a full city's tower-stronghold (v49) will not work here. His approach to the door of the tower positions him directly under the woman's hand (v53). The anti-covenant king who sowed salt to prevent covenant fruitfulness will be brought down by a woman performing a household task — the millstone (<em>pelah-rekaḵ</em>, v53) is a tool of grain-processing, the covenant's most basic provision.</p>",
    "55": "<p><em>wayyirʾû ʾîš-yiśrāʾēl kî mēt ʾăḇîmeleḵ wayyēlkû ʾîš limqōmô</em> — 'When the men of Israel saw that Abimelech was dead, they all went home to their own places.' The dissolution of the force is immediate and total: without the charismatic/coercive center, the army simply disperses. There is no mourning, no burial record (contrast the minor judges' burial notices — v2, v5), no successor: Abimelech leaves nothing behind. <em>wayyēlkû ʾîš limqōmô</em> (each went to his own place) — the idiom of peaceful dispersal after the battle (cf. 1 Sam 13:2), but here it signals not covenant victory but the end of an anti-covenant episode with no legacy.</p>",
    "56": "<p><em>wayyāšeḇ ʾĕlōhîm ʾet rāʿat ʾăḇîmeleḵ ʾăšer ʿāśāh ləʾāḇîw lahărōg ʾet-šibʿîm ʾeḥāyw</em> — 'Thus God repaid the evil of Abimelech which he had done to his father by killing his seventy brothers.' The double divine-retribution summary (v56 for Abimelech, v57 for Shechem) frames the whole chapter as YHWH's moral governance even when YHWH's name is absent from most of the narrative. <em>šûḇ rāʿat</em> (returned the evil) — lex talionis operating at the cosmic level: the bloodguilt (<em>ḥāmās</em>, v24) returns precisely on those who spilled it. The narrator is explicit: this is not chance or military contingency — God repaid. The passive instruments (the evil spirit, Gaal, the woman's millstone) are all YHWH's agents.</p>"
  },
  "10": {
    "2": "<p><em>wayyišpōṭ ʾet-yiśrāʾēl ʿeśrîm ûšəlōš šānāh wayyāmot wayyiqqāḇēr bəšāmîr</em> — 'He judged Israel twenty-three years. Then he died and was buried at Shamir.' The minor judge notice for Tola follows the minimalist formula: years of service, death, burial. <em>Šāmîr</em> — the burial site, in the hill country of Ephraim (v1), likely a different Shamir from the Judean site (Josh 15:48). The twenty-three years of stable judging (immediately after Abimelech's three-year catastrophe) represent covenant normalcy: the minor judges hold the land in peace, their very uneventfulness testifying to successful governance.</p>",
    "4": "<p><em>wayhî-lô šəlōšîm bānîm rōkəḇîm ʿal-šəlōšîm ʿayārîm ûšəlōšîm ʿărāyôt lāhem bəʾereṣ haggileʿāḏ wattiqqārēʾ lāhem Ḥawwôt-yāʾîr ʿaḏ hayyôm hazzeh</em> — 'He had thirty sons riding on thirty donkeys, and they had thirty cities in Gilead, which are called Havvoth-jair to this day.' <em>rōkəḇîm ʿal-ʿayārîm</em> (riding on young donkeys) — the donkey is the royal/judicial mount (cf. Judg 5:10; Zech 9:9). Thirty judge-sons administering thirty cities represents either efficient decentralized justice or dynastic patronage nepotism — the text is neutral, but the pattern of judge-sons taking administrative roles signals the drift toward hereditary rule that will produce Abimelech (9:1). <em>Ḥawwôt-yāʾîr</em> (villages of Jair) — the place-name preserves Jair's administrative legacy (cf. Num 32:41).</p>",
    "5": "<p><em>wayyāmot yāʾîr wayyiqqāḇēr bəqāmôn</em> — 'Jair died and was buried at Kamon.' The minor judge's death-and-burial notice is the most compressed in Judges: seven Hebrew words. Kamon is unidentified; the narrator records only that Jair's bones lie in an unknown Gileadite town. The brevity itself is the commentary: these judges served, died, and were buried — no monuments, no successors, no divine speeches. Their fruitfulness was the peace of their years, not the drama of their exploits.</p>",
    "8": "<p><em>wayyirʿăṣû wayyirṣəṣû ʾet-bənê yiśrāʾēl bašānāh hahîʾ šəmoneh ʿeśrēh šānāh ʾet kol-bənê yiśrāʾēl ʾăšer bəʿēḇer hayyardēn bəʾereṣ hāʾĕmorî ʾăšer baggileʿāḏ</em> — 'That year they shattered and crushed (<em>wayyirʿăṣû wayyirṣəṣû</em>) the sons of Israel — eighteen years — all the sons of Israel who were across the Jordan in the land of the Amorites, which is in Gilead.' The doubled verb <em>rāʿaṣ…rāṣaṣ</em> (H7492/H7533, shattered and crushed) uses intensive repetition for severe oppression — the same pair used for God's judgment on Israel's enemies in Ps 68:21. Eighteen years is the longest oppression period in Judges (cf. Mesopotamian oppression, 3:8 — eight years; Moab — 18 years; Hazor — 20 years; Midian — 7 years). The Gileadite focus prepares for Jephthah's story (ch11).</p>",
    "9": "<p><em>wayyaʿaḇrû bənê-ʿammôn ʾet-hayyardēn lěhilāḥem gam-bîhûḏāh ûḇinyāmîn ûḇəḇêt ʾeprayim wayyēṣar ləyiśrāʾēl meʾōd</em> — 'The sons of Ammon also crossed the Jordan to fight against Judah and Benjamin and the house of Ephraim, so that Israel was greatly distressed.' The Ammonite crossing of the Jordan inverts the conquest narrative: Israel crossed the Jordan to take the land (Josh 3-4); now the enemy crosses the Jordan to take it back. The tribal list (Judah, Benjamin, Ephraim) shows the oppression spreading westward from Gilead — the entire covenant territory is threatened. <em>wayyēṣar ləyiśrāʾēl meʾōd</em> (Israel was greatly distressed) — the phrase triggers the next element of the cycle: Israel crying out to YHWH (v10).</p>",
    "11": "<p><em>wayyōʾmer YHWH ʾel-bənê yiśrāʾēl halōʾ mimmitsrayim ûmin-hāʾĕmorî ûmibnê ʿammôn ûmin-pəlištîm</em> — 'YHWH said to the sons of Israel: Was it not from the Egyptians and from the Amorites and from the sons of Ammon and from the Philistines...' YHWH's direct speech to Israel is extremely rare in Judges (cf. 2:1-3; 6:8-10); the divine address here is a covenant lawsuit (<em>rîḇ</em>) listing the deliverances that create obligation. The exodus from Egypt heads the list — the foundational deliverance that grounds all subsequent claims. The Ammonites are listed among those YHWH previously defeated, making their current success all the more pointed: the oppressor YHWH once defeated is now defeating Israel because Israel forgot YHWH.</p>",
    "12": "<p><em>wəṣîḏônîm wăʾAmālēq ûMāʿôn lāḥăṣû ʾetkem wayttsʿaqû ʾēlay wāʾôšîʿāh ʾetkem miyyāḏām</em> — 'When the Sidonians and the Amalekites and the Maonites oppressed you, you cried out to me, and I saved you from their hand.' The list of deliverances (vv11-12) functions as YHWH's covenant resume: repeated rescue from multiple enemies constitutes a pattern of grace that Israel has repeatedly spurned. The Maonites (Meunim, Arabian tribe) and Sidonians add geographic breadth: YHWH's deliverances span Transjordan, Canaan, the Philistine coast, and Arabia. The exhaustive list makes the refusal of v13 proportional — the pattern of forgiveness has been worn out by the pattern of apostasy.</p>",
    "13": "<p><em>wəʾattem ʿăzaḇtem ʾôtî wataʿaḇdû ʾĕlōhîm ʾăḥērîm lākēn lōʾ-ʾôsîp ləhôšîaʿ ʾetkem</em> — 'Yet you have forsaken me and served other gods; therefore I will save you no more.' <em>ʿāzaḇ</em> (H5800, to forsake, abandon) — the covenant-disloyalty verb; Israel forsook YHWH as a man forsakes a wife (Jer 1:16, 2:13). The consequence is stated with startling directness: <em>lōʾ-ʾôsîp ləhôšîaʿ ʾetkem</em> (I will not continue to save you) — the suspension of the saving relationship. This is the one place in Judges where YHWH explicitly refuses to act; the refusal is temporary (v16b: 'he could bear Israel's misery no longer') but it stands as the theological highpoint of the chapter: grace is not automatic; covenant abandonment has consequences.</p>",
    "15": "<p><em>wayyōʾmərû bənê yiśrāʾēl ʾel-YHWH ḥāṭāʾnû ʿăśēh-ʾattāh lānû kəkol-haṭṭôḇ bəʿênêkā ʾak haṣṣîlēnû nāʾ hayyôm hazzeh</em> — 'The sons of Israel said to YHWH: We have sinned. Do to us whatever seems good in your eyes; only please deliver us this day.' The confession <em>ḥāṭāʾnû</em> (we have sinned) is the seventh occurrence of Israel's sin-cycle in Judges, but this time it is accompanied by genuine submission: <em>ʿăśēh ʾattāh lānû kəkol-haṭṭôḇ bəʿênêkā</em> (do to us whatever seems good in your eyes) — covenantal surrender of the plea, accepting YHWH's judgment as just. The grammar shifts from demand (previous cycles: 'save us') to submission. This submission, combined with the removal of foreign gods (v16a), triggers YHWH's relenting.</p>",
    "17": "<p><em>wayyiṣṣāʿăqû bənê ʿammôn wayyaḥănû baggileʿāḏ wayyēʾāsəpû bənê yiśrāʾēl wayyaḥănû hammitsəpāh</em> — 'Then the sons of Ammon were called to arms and camped in Gilead, and the sons of Israel gathered and camped at Mizpah.' The military dispositions create the geographic tension: Ammon in Gilead, Israel at Mizpah. <em>Hammitsəpāh</em> (the Watchtower/Lookout) in Gilead is the same site where Jacob and Laban made their covenant (Gen 31:49: 'YHWH watch between you and me'). Israel's camp at this covenant-witness site as they prepare to face Ammon is the narrator's spatial theology: they are gathering at the place where covenant fidelity is watched over, having just recommitted to YHWH.</p>",
    "18": "<p><em>wayyōʾmərû hāʿām śārê gilʿāḏ ʾîš ʾel-rēʿēhû mî hāʾîš ʾăšer yaḥēl lāhilāḥem bibnê ʿammôn yihyeh lərōʾš lekol yōšəḇê gilʿāḏ</em> — 'The people and leaders of Gilead said to one another: Who is the man who will begin the fight against the sons of Ammon? He will be head over all the inhabitants of Gilead.' The leadership vacuum created by the apostasy (no judge raised yet) produces a conditional kingship offer: military success earns political leadership. The phrase <em>rōʾš lekol yōšəḇê gilʿāḏ</em> (head over all the inhabitants of Gilead) anticipates Jephthah's negotiation in 11:6-11, where he demands this title before agreeing to fight. The community is offering what Jephthah will secure through hard bargaining — his marginalization (11:2-3) gives him the leverage to convert crisis into covenant appointment.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'judges')
    merge_comm(c, JUDGES_FILL)
    save_comm('mkt-original', 'judges', c)

    import json
    inter = json.load(open(ROOT / 'data' / 'interlinear' / 'judges.json'))
    total_miss = 0
    for ch in ['9', '10']:
        miss = [v for v in inter[ch] if v not in c.get(ch, {})]
        total = len(inter[ch])
        have = len(c.get(ch, {}))
        if miss:
            print(f'  ch {ch}: MISSING {sorted(miss, key=int)} ({have}/{total})')
            total_miss += len(miss)
        else:
            print(f'  ch {ch}: complete ({have}/{total})')
    if total_miss == 0:
        all_miss = sum(1 for ch in inter for v in inter[ch] if v not in c.get(str(ch) if isinstance(ch,int) else ch, {}))
        print(f'  Overall judges/original: {sum(len(inter[ch]) for ch in inter) - all_miss}/{sum(len(inter[ch]) for ch in inter)}')

if __name__ == '__main__':
    main()
